package be.schaubroeck.lpb.rkm.rekenmotor.check;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;

import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.FISCAAL_JAAR_KEY;

public class CheckRegimeLoonElementen {

    public void check(RekenContext mainContext, Opdracht opdracht) {
        LoonElementManager manager = mainContext.getLoonElementManager();
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        Integer fiscaalJaar = mainContext.getInteger(FISCAAL_JAAR_KEY);
        Hoedanigheid hoedanigheid = opdracht.getHoedanigheid();
        boolean caseGeenRegime5 = hoedanigheid == Hoedanigheid.ERKENTELIJKHEIDSPREMIE;
        boolean caseGeenRegime5VoorGrens =
                hoedanigheid == Hoedanigheid.VRIJWILLIGE_BRANDWEER_ERKENTELIJKHEIDSPREMIE && fiscaalJaar < BvTools.GRENS_FISCAAL_REGIME_5;
        boolean caseGeenRegimeFiche13 = fiscaalJaar < BvTools.GRENS_REGIME_FICHE_281_13;

        if (caseGeenRegime5VoorGrens || caseGeenRegime5 || caseGeenRegimeFiche13) {
            RegulManager regulManager = mainContext.getRegulManager();
            for (LoonElement element : loonElementen) {
                LnedefRegBv regime = element.getAardKodeExtensie().getRegimeBv();
                if (regime == LnedefRegBv.VD_BV_10_BZ___VB && (caseGeenRegime5VoorGrens || caseGeenRegime5)) {
                    Regulkode regulKode = caseGeenRegime5 ? Regulkode.GEEN_FISCAAL_REGIME_5_TOEGELATEN : Regulkode.FISCAAL_REGIME_5_PAS_VANAF_2006;
                    regulManager.doRegulException(opdracht, regulKode);
                } else {
                    if (regime == LnedefRegBv.VD_BV_13_TIJDELIJKE_WERKLOOSHEID && caseGeenRegimeFiche13) {
                        regulManager.doRegulException(opdracht, Regulkode.FICHE_281_13_VANAF_FJ_2015);
                    }
                }
            }
        }
    }
}
